    final User user = (User)session.getAttribute("USER");

    final Path rollbackFilePath = Paths.get("cust", "def", "app", apname + path, "history", fileName);
    final Path doneRollbackFilePath = Paths.get("cust", "def", "app", apname + path, "history", fileName.replace(".massUpdateRollback.", ".massUpdateRollbackDone."));
    if (!Files.exists(rollbackFilePath) || si == -1) return;

    final NUIForm form = AppManager.getFormPage(apname, path, si);
    if (form == null) return;
    final JSONObject rollbackJo = new JSONObject(FileHelper.readFileToString(rollbackFilePath.toFile()));

    final List<MassRollbackAction> rollbackActions = new ArrayList<>();

    boolean ifCheckRootNodeId = true;
    final List<Integer> rollbackedRootNodeId = new ArrayList<>();
    Iterator keys = rollbackJo.keys();
    while (keys.hasNext()) {
        String key = (String) keys.next();
        int domainId = Encoder.parseInt(key, -1);
        JSONArray rollbackEntries = rollbackJo.optJSONArray(key);
        if (domainId != -1 && rollbackEntries != null) {
            MassRollbackAction action = MassRollbackActionGetter.getRollbackAction(form, domainId, rollbackEntries);
            if (action != null) {
                rollbackActions.add(action);
            }

            if(ifCheckRootNodeId) {
                for(int i = 0 ; i < rollbackEntries.length(); i++) {
                    JSONObject rollbackEntry = rollbackEntries.optJSONObject(i);
                    int rootNodeId = Encoder.parseInt(rollbackEntry.optString("rootNodeId"), -1);
                    if(rootNodeId != -1) rollbackedRootNodeId.add(rootNodeId);
                }
                ifCheckRootNodeId = false;
            }
        }
    }
    SystemTaskProgress.setStatus(apname, Const.STP_MASSROLL, "Initializing...", 0, SystemTaskProgress.Status.PROCESSING);
